class VendingMachine:
    def __init__(self, balance=0):
        self.balance = balance
        self.inventory = {}

    def add_funds(self, amount):
        self.balance += amount

    def restock(self, item, price, quantity):
        self.inventory[item] = {'price': price, 'quantity': quantity}

    def vend(self, item):
        if item not in self.inventory or self.inventory[item]['quantity'] == 0:
            return f'{item} is out of stock'
        price = self.inventory[item]['price']
        if self.balance < price:
            return f'Insufficient funds, please add {price - self.balance}'
        self.balance -= price
        self.inventory[item]['quantity'] -= 1
        return item


# Testhelfer – nicht ändern
def test_vend(balance, item, price, quantity):
    vm = VendingMachine(balance)
    vm.restock(item, price, quantity)
    return vm.vend(item)

