import math

class Triangle:
    def __init__(self, a, b, c):
        self.sides = sorted([a, b, c])

    def perimeter(self):
        return sum(self.sides)

    def area(self):
        a, b, c = self.sides
        s = self.perimeter() / 2
        return math.sqrt(s * (s - a) * (s - b) * (s - c))

    def is_right(self):
        a, b, c = self.sides
        return abs(a**2 + b**2 - c**2) < 1e-9

    def side_classification(self):
        a, b, c = self.sides
        if a == b == c:
            return 'equilateral'
        elif a == b or b == c:
            return 'isosceles'
        else:
            return 'scalene'


# Testhelfer – nicht ändern
def test_area(a, b, c):
    return round(Triangle(a, b, c).area(), 2)

