import math

class Vector:
    def __init__(self, *args):
        self.data = list(args)

    def as_list(self):
        return self.data

    def size(self):
        return len(self.data)

    def magnitude(self):
        return math.sqrt(sum(x**2 for x in self.data))

    def __add__(self, other):
        return Vector(*[a + b for a, b in zip(self.data, other.data)])

    def __sub__(self, other):
        return Vector(*[a - b for a, b in zip(self.data, other.data)])

    def euclidean_distance(self, other):
        return (self - other).magnitude()

    def cosine_similarity(self, other):
        dot = sum(a * b for a, b in zip(self.data, other.data))
        return dot / (self.magnitude() * other.magnitude())


# Testhelfer – nicht ändern
def test_magnitude(components):
    return round(Vector(*components).magnitude(), 4)
